import json

good = '{"email": "maya@pyloft.dev", "severity": 3}'
no_email = '{"severity": 3}'
bad_severity = '{"email": "maya@pyloft.dev", "severity": 9}'

def safe_extract(raw):
    try:
        data = json.loads(raw)
    except json.JSONDecodeError:
        return {"ok": False, "error": "bad json"}
    if "email" not in data or not isinstance(data["email"], str) or not data["email"]:
        return {"ok": False, "error": "missing email"}
    sev = data.get("severity")
    if not isinstance(sev, int) or sev < 1 or sev > 5:
        return {"ok": False, "error": "bad severity"}
    return {"ok": True, "data": data}

for raw in [good, no_email, bad_severity]:
    result = safe_extract(raw)
    if result["ok"]:
        print(f"ok=True email={result['data']['email']}")
    else:
        print(f"ok=False error={result['error']}")
